  "cases": [
    {
      "input": {
        "config": {},
        "steps": [
          {
            "action": "produce",
            "topic": "topic-name-1",
            "messages": [
              {
                "value": "testing message content"
              }
            ],
            "clientResponse": {
              "status": "success",
              "records": []
            }
          },
          {
            "action": "consume_batch",
            "topic": "topic-name-1",
            "partition": 0,
            "messages": [
              {
                "value": "",
